function AlbumCover({ album, size = 92, listened = false }) {
  const { BLUE } = useTheme();
  const rawUrl = album?.coverArtUrl && album.coverArtUrl !== "none" ? album.coverArtUrl.replace("http://", "https://") : null;
  const [imgFailed, setImgFailed] = useState(false);
  useEffect(() => { setImgFailed(false); }, [rawUrl]);
  const coverUrl = imgFailed ? null : rawUrl;
  const radius = 0; // squared per redesign
  const offset = Math.round(size * 0.06);
  const pill = listened ? (
    <span
      aria-hidden="true"
      style={{
        position: "absolute",
        top: offset,
        left: offset,
        display: "inline-flex",
        alignItems: "center",
        gap: 4,
        padding: "4px 10px 4px 8px",
        background: BLUE,
        color: "#fff",
        fontSize: 10.5,
        fontWeight: 700,
        letterSpacing: "0.03em",
        borderRadius: 0,
        boxShadow: `0 2px 6px ${BLUE}80`,
        lineHeight: 1,
        zIndex: 2,
        fontFamily: "'Helvetica Neue', Helvetica, Arial, sans-serif",
      }}
    >
      <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="3.6" strokeLinecap="round" strokeLinejoin="round">
        <path d="M4 12.5l5 5L20 6" />
      </svg>
      Listened
    </span>
  ) : null;

  if (coverUrl) {
    return (
      <div style={{ position: "relative", width: size, height: size, flexShrink: 0 }}>
        <img
          src={coverUrl}
          alt=""
          loading="lazy"
          decoding="async"
          onError={() => setImgFailed(true)}
          style={{ width: size, height: size, borderRadius: radius, objectFit: "cover", display: "block" }}
        />
        {pill}
      </div>
    );
  }
  return (
    <div
      style={{
        position: "relative",
        width: size,
        height: size,
        background: BLUE,
        borderRadius: radius,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        flexShrink: 0,
      }}
    >
      <HeadphoneMark size={size * 0.4} color="#fff" />
      {pill}
    </div>
  );
}

