// Full song mix detail screen: Spotify/Apple-Music-style sequential
// tracklist, with an "add track" flow (search album -> type track title)
// and a custom cover image upload, both only available to the mix owner.
// Shared tag display + editor used by both album mix and song mix detail
// pages. Owners see an input that adds tags on Enter/comma; everyone sees
// clickable tag pills that navigate to tag results.
// Renders @mentions in comment text as styled blue spans
function CommentText({ text }) {
  const { BLUE } = useTheme();
  const parts = text.split(/(@[\w.]+)/g);
  return (
    <span>
      {parts.map((part, i) =>
        part.startsWith("@")
          ? <span key={i} style={{ color: BLUE, fontWeight: 600 }}>{part}</span>
          : <span key={i}>{part}</span>
      )}
    </span>
  );
}

// Input with @mention autocomplete
function CommentInput({ placeholder, onSubmit, currentUsername, initialValue = "" }) {
  const { BLUE, INK, LINE, MUTE, BG } = useTheme();
  const [text, setText] = useState(initialValue);
  const [mentionQuery, setMentionQuery] = useState(null);
  const [mentionStart, setMentionStart] = useState(0);

  const mentionResults = useMemo(() => {
    if (mentionQuery === null) return [];
    return ALL_USERS.filter((u) =>
      u.username.toLowerCase().includes(mentionQuery.toLowerCase()) ||
      u.displayName.toLowerCase().includes(mentionQuery.toLowerCase())
    ).slice(0, 5);
  }, [mentionQuery]);

  function handleChange(e) {
    const val = e.target.value;
    setText(val);
    const cursor = e.target.selectionStart;
    const before = val.slice(0, cursor);
    const match = before.match(/@([\w.]*)$/);
    if (match) { setMentionQuery(match[1]); setMentionStart(cursor - match[0].length); }
    else setMentionQuery(null);
  }

  function insertMention(username) {
    const after = text.slice(mentionStart + (mentionQuery !== null ? mentionQuery.length + 1 : 0));
    setText(text.slice(0, mentionStart) + `@${username} ` + after);
    setMentionQuery(null);
  }

  function handleKeyDown(e) {
    if (e.key === "Enter" && !e.shiftKey && text.trim()) { e.preventDefault(); onSubmit(text.trim()); setText(""); setMentionQuery(null); }
    if (e.key === "Escape") setMentionQuery(null);
  }

  return (
    <div style={{ position: "relative" }}>
      <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
        <Avatar username={currentUsername} size={30} />
        <div style={{ flex: 1, display: "flex", alignItems: "center", gap: 8, background: "#ffffff", border: "1px solid #e3e6ea", borderRadius: 0, padding: "2px 4px 2px 14px" }}>
          <input
            style={{ flex: 1, border: "none", outline: "none", background: "none", fontSize: 14, color: "#1a1a1a", padding: "7px 0", fontFamily: "inherit" }}
            placeholder={placeholder || "Write a comment..."}
            value={text}
            onChange={handleChange}
            onKeyDown={handleKeyDown}
          />
          <button
            onClick={() => { if (text.trim()) { onSubmit(text.trim()); setText(""); setMentionQuery(null); } }}
            disabled={!text.trim()}
            style={{ border: "none", background: text.trim() ? BLUE : "#c2c7cc", color: "#fff", fontWeight: 400, fontSize: 13, padding: "6px 14px", borderRadius: 0, cursor: text.trim() ? "pointer" : "default", transition: "background 0.12s", fontFamily: "inherit" }}
          >
            Post
          </button>
        </div>
      </div>
      {mentionQuery !== null && mentionResults.length > 0 && (
        <div style={{ position: "absolute", top: "100%", left: 50, zIndex: 20, background: BG, border: `1px solid ${LINE}`, borderRadius: 0, marginTop: 4, minWidth: 180, boxShadow: "0 4px 12px rgba(0,0,0,0.12)" }}>
          {mentionResults.map((u) => (
            <div key={u.username} onClick={() => insertMention(u.username)} className="ui-sans" style={{ padding: "8px 12px", cursor: "pointer", display: "flex", alignItems: "center", gap: 8, fontSize: 13 }} onMouseEnter={(e) => e.currentTarget.style.background = LINE} onMouseLeave={(e) => e.currentTarget.style.background = "transparent"}>
              <Avatar username={u.username} size={20} />
              <div><div style={{ fontWeight: 600 }}>{u.displayName}</div><div style={{ fontSize: 11, color: MUTE }}>@{(u.username || "").toLowerCase()}</div></div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// Renders a single comment node with its nested replies, recursively
function CommentNode({ comment, depth = 0, reviewId, onReply, currentUsername, reviewReactions = {}, onReact, onOpenProfile }) {
  const { BLUE, INK, LINE, MUTE } = useTheme();
  const [replying, setReplying] = useState(false);
  const avatarSize = 32;
  const fontSize = 14;

  function relativeTime(date) {
    if (!date) return "";
    const diff = Date.now() - new Date(date).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 60) return mins + "m";
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return hrs + "h";
    const days = Math.floor(hrs / 24);
    if (days < 30) return days + "d";
    const mos = Math.floor(days / 30);
    if (mos < 12) return mos + "mo";
    return Math.floor(mos / 12) + "y";
  }

  const youHearted = ((reviewReactions[comment.id] || {}).heart || []).includes(currentUsername);

  return (
    <div style={{ marginLeft: depth > 0 ? 50 : 0 }}>
      <div style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
        <Avatar username={comment.username} size={avatarSize} />
        <div style={{ flex: 1, minWidth: 0 }}>
          <p style={{ margin: 0, fontSize, lineHeight: 1.45, color: "#2a2a2a", fontFamily: "inherit" }}>
            <span style={{ fontWeight: 700, cursor: comment.username !== currentUsername ? "pointer" : "default" }} onClick={(e) => { e.stopPropagation(); if (comment.username !== currentUsername && onOpenProfile) onOpenProfile(comment.username); }}>{comment.username === currentUsername ? "you" : "@" + (comment.username || "").toLowerCase()}</span>
            {"  "}
            <CommentText text={comment.text} />
          </p>
          <div style={{ display: "flex", alignItems: "center", gap: 14, marginTop: 6, fontSize: 13, color: "#9aa0a6", fontWeight: 400 }}>
            {comment.date && <span style={{ fontWeight: 400 }}>{relativeTime(comment.date)}</span>}
            <button
              onClick={() => setReplying((r) => !r)}
              style={{ border: "none", background: "none", padding: 0, cursor: "pointer", font: "inherit", color: replying ? "#1a1a1a" : "#9aa0a6", fontSize: 13, fontWeight: 400 }}
            >
              {replying ? "cancel" : "Reply"}
            </button>
            {comment.id && onReact && (
              <button
                onClick={() => onReact(comment.id, "heart")}
                style={{ border: "none", background: "none", padding: 0, cursor: "pointer", display: "flex", alignItems: "center", gap: 4, color: youHearted ? BLUE : "#c9ced4", fontSize: 13 }}
              >
                <Heart size={13} fill={youHearted ? BLUE : "none"} strokeWidth={1.6} />
                {((reviewReactions[comment.id] || {}).heart || []).length > 0 && (
                  <span style={{ fontSize: 12 }}>{((reviewReactions[comment.id] || {}).heart || []).length}</span>
                )}
              </button>
            )}
          </div>
        </div>
      </div>

      {(comment.replies || []).map((reply) => (
        <div key={reply.id} style={{ marginTop: 16 }}>
          <CommentNode comment={reply} depth={depth + 1} reviewId={reviewId} onReply={onReply} currentUsername={currentUsername} reviewReactions={reviewReactions} onReact={onReact} onOpenProfile={onOpenProfile} />
        </div>
      ))}

      {replying && (
        <div style={{ marginTop: 10, marginLeft: 50 }}>
          <CommentInput
            placeholder={"reply to @" + comment.username + "..."}
            initialValue={"@" + comment.username + " "}
            currentUsername={currentUsername}
            onSubmit={(text) => { onReply(reviewId, comment.id, comment.username, text); setReplying(false); }}
          />
        </div>
      )}
    </div>
  );
}

function countReplies(comment) {
  if (!comment.replies || comment.replies.length === 0) return 0;
  return comment.replies.length + comment.replies.reduce((s, r) => s + countReplies(r), 0);
}

function countAllComments(comments) {
  return comments.reduce((s, c) => s + 1 + countReplies(c), 0);
}

function ReviewComments({ reviewId, comments = [], onAdd, onReply, currentUsername, reviewOwnerUsername, reviewReactions = {}, onReact, onLoadReactions, onOpenProfile, startOpen = false }) {
  const { BLUE, INK, LINE, MUTE, BG } = useTheme();
  const [open, setOpen] = useState(startOpen);
  const total = countAllComments(comments);

  function handleToggle() {
    const next = !open;
    setOpen(next);
    if (next && onLoadReactions && comments.length > 0) {
      function collectIds(cs) {
        const ids = [];
        for (const c of cs) {
          if (c.id) ids.push(c.id);
          if (c.replies && c.replies.length) ids.push(...collectIds(c.replies));
        }
        return ids;
      }
      onLoadReactions(collectIds(comments));
    }
  }

  return (
    <div className="sb-comment-bubble" style={{ background: "#fafbfc", borderTop: "1px solid #eceef0", marginTop: 10, marginLeft: -16, marginRight: -16, marginBottom: -14, borderRadius: 0, padding: "0 16px" }}>
      {!startOpen && (
        <button
          className="ui-sans"
          onClick={handleToggle}
          style={{ display: "flex", alignItems: "center", gap: 8, border: "none", background: "none", padding: "14px 0 0 0", cursor: "pointer", fontSize: 13, fontWeight: 400, color: "#6b7280", letterSpacing: "0.01em", fontFamily: "inherit" }}
          onMouseEnter={(e) => e.currentTarget.style.color = "#1a1a1a"}
          onMouseLeave={(e) => e.currentTarget.style.color = "#6b7280"}
        >
          {total > 0 ? total + " comment" + (total !== 1 ? "s" : "") : ""}
          {total > 0 && (
            <span style={{ fontSize: 11, display: "inline-block", transition: "transform 0.2s", transform: open ? "rotate(180deg)" : "rotate(0deg)" }}>&#9660;</span>
          )}
        </button>
      )}

      {(open || total === 0) && (
        <>
          {comments.length > 0 && (
            <div style={{ maxHeight: 360, overflowY: "auto", padding: "20px 16px 6px", display: "flex", flexDirection: "column", gap: 22 }}>
              {comments.map((c) => (
                <CommentNode key={c.id} comment={c} depth={0} reviewId={reviewId} onReply={onReply} currentUsername={currentUsername} reviewReactions={reviewReactions} onReact={onReact} onOpenProfile={onOpenProfile} />
              ))}
            </div>
          )}
          <div style={{ borderTop: comments.length > 0 ? "1px solid #eceef0" : "none", marginTop: comments.length > 0 ? 20 : 12, paddingTop: comments.length > 0 ? 14 : 0, paddingBottom: 22, paddingLeft: 16, paddingRight: 16 }}>
            <CommentInput
              placeholder="Write a comment..."
              currentUsername={currentUsername}
              onSubmit={(text) => onAdd(reviewId, text, reviewOwnerUsername)}
            />
          </div>
        </>
      )}
      {!open && total > 0 && <div style={{ height: 18 }} />}
    </div>
  );
}
